package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Author  string
	Content string
}

var comments = []Comment{
	{Author: "Alice", Content: "This is a <b>bold</b> comment!"},
	{Author: "Bob", Content: "This is an <i>italic</i> comment!"},
}

var tmpl = template.Must(template.New("comments").Parse(`
<!DOCTYPE html>
<html>
<head>
	<title>User Comments</title>
</head>
<body>
	<h1>User Comments</h1>
	{{range .}}
		<div>
			<strong>{{.Author}}</strong>: <span>{{.Content | safeHTML}}</span>
		</div>
	{{end}}
</body>
</html>
`))

func safeHTML(s string) template.HTML {
	return template.HTML(s)
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	err := tmpl.Execute(w, comments)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	http.ListenAndServe(":8080", nil)
}